   317→								<SelectItem value="avg_duration">Avg Duration (min)</SelectItem>
   318→								<SelectItem value="total_duration">
   319→									Total Duration (hours)
   320→								</SelectItem>
   321→								<SelectItem value="avg_tokens">Avg Tokens</SelectItem>
