   337→						<Select
   338→							value={selectedDimension}
   339→							onValueChange={(v) =>
   340→								setSelectedDimension(v as DimensionAnalysisInput["dimension"])
   341→							}
   342→						>
   343→							<SelectTrigger className="w-full">
   344→								<SelectValue />
   345→							</SelectTrigger>
   346→							<SelectContent>
   347→								<SelectItem value="session_archetype">Session Type</SelectItem>
   348→								<SelectItem value="model_used">Model Used</SelectItem>
