   363→						<Select
   364→							value={selectedSplitBy || "none"}
   365→							onValueChange={(v) => {
   366→								const value = v === "none" ? "" : v;
   367→								setSelectedSplitBy(
   368→									value as DimensionAnalysisInput["dimension"] | "",
   369→								);
   370→								if (!value) setShowPercentage(false);
   371→							}}
   372→						>
   373→							<SelectTrigger className="w-full">
   374→								<SelectValue />
   375→							</SelectTrigger>
   376→							<SelectContent>
   377→								<SelectItem value="none">None</SelectItem>
   378→								<SelectItem value="session_archetype">Session Type</SelectItem>
   379→								<SelectItem value="model_used">Model Used</SelectItem>
