	DeveloperCostBreakdown,
	ProjectCostBreakdown,
} from "@rudel/api-routes";
import type { ColumnDef } from "@tanstack/react-table";
import {
	Activity,
	DollarSign,
	Target,
	TrendingDown,
	TrendingUp,
} from "lucide-react";
