						<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
							<div>
								<label
									htmlFor="codePercentage"
									className="block text-sm font-medium text-subheading mb-1"
								>
									Code Percentage (%)
								</label>
								<Input
									id="codePercentage"
									type="number"
									value={roiInputs.codePercentage}
									onChange={(e) =>
										setRoiInputs({
											...roiInputs,
											codePercentage: parseFloat(e.target.value) || 0,
										})
									}
									min={0}
									max={100}
								/>
								<p className="text-xs text-muted mt-1">
									% of output that is actual code
								</p>
							</div>
							<div>
								<label
									htmlFor="tokensPerLOC"
									className="block text-sm font-medium text-subheading mb-1"
								>
									Tokens per LOC
								</label>
								<Input
									id="tokensPerLOC"
									type="number"
									value={roiInputs.tokensPerLOC}
									onChange={(e) =>
										setRoiInputs({
											...roiInputs,
											tokensPerLOC: parseFloat(e.target.value) || 1,
										})
									}
									min={1}
								/>
								<p className="text-xs text-muted mt-1">
									Average tokens per line of code
								</p>
							</div>
							<div>
								<label
									htmlFor="locPerHour"
									className="block text-sm font-medium text-subheading mb-1"
								>
									LOC per Hour (baseline)
								</label>
								<Input
									id="locPerHour"
									type="number"
									value={roiInputs.locPerHour}
									onChange={(e) =>
										setRoiInputs({
											...roiInputs,
											locPerHour: parseFloat(e.target.value) || 1,
										})
									}
									min={1}
								/>
								<p className="text-xs text-muted mt-1">
									Manual coding speed without Claude
								</p>
							</div>
							<div>
								<label
									htmlFor="devHourlyRate"
									className="block text-sm font-medium text-subheading mb-1"
								>
									Developer Rate ($/hr)
								</label>
								<Input
									id="devHourlyRate"
									type="number"
									value={roiInputs.devHourlyRate}
									onChange={(e) =>
										setRoiInputs({
											...roiInputs,
											devHourlyRate: parseFloat(e.target.value) || 1,
										})
									}
									min={1}
								/>
								<p className="text-xs text-muted mt-1">Hourly developer cost</p>
							</div>
						</div>
						<div className="mt-4">
							<Button variant="outline" size="sm" onClick={resetToDefaults}>
								Reset to Defaults
							</Button>
						</div>
					</AnalyticsCard>

					{/* KPI Cards */}
					<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
						<StatCard
							title="Total Spend"
							value={formatCurrency(metrics.total_cost)}
							icon={DollarSign}
							iconColor="text-red-600"
							trend={{ value: metrics.total_cost_change_pct }}
						/>
						<StatCard
							title="Cost per Commit"
							value={
								metrics.cost_per_commit > 0
									? formatCurrency(metrics.cost_per_commit)
									: "N/A"
							}
							icon={Target}
							iconColor="text-blue-600"
							trend={{ value: metrics.cost_per_commit_change_pct }}
						/>
						<StatCard
							title="Dev Hours Saved"
							value={`${formatCompact(calculatedROI.hoursSaved)}h`}
							icon={Activity}
							iconColor="text-green-600"
							trend={{ value: metrics.dev_hours_saved_change_pct }}
						/>
						<StatCard
							title="Dollar Value Saved"
							value={`$${formatCompact(calculatedROI.dollarValueSaved)}`}
							icon={
								calculatedROI.roiPercentage >= 0 ? TrendingUp : TrendingDown
							}
							iconColor={
								calculatedROI.roiPercentage >= 0
									? "text-green-600"
									: "text-red-600"
							}
						/>
					</div>

					{/* ROI Breakdown */}
					<AnalyticsCard className="mb-8">
						<div className="mb-4">
							<h3 className="text-lg font-semibold text-heading">
								ROI Calculation Breakdown
							</h3>
						</div>
						<div className="bg-surface rounded-lg p-6 font-mono text-sm">
							<div className="space-y-2">
								<div className="flex justify-between">
									<span className="text-muted">Output Tokens:</span>
									<span className="font-semibold text-foreground">
										{formatCompact(metrics.output_tokens)}
									</span>
								</div>
								<div className="flex justify-between">
									<span className="text-muted">
										Code % ({roiInputs.codePercentage}%):
									</span>
									<span className="font-semibold text-foreground">
										{formatCompact(calculatedROI.loc)} LOC
									</span>
								</div>
								<div className="flex justify-between border-b border-border pb-2">
									<span className="text-muted">
										Hours Saved (LOC / {roiInputs.locPerHour}):
									</span>
									<span className="font-semibold text-foreground">
										{formatCompact(calculatedROI.hoursSaved)} hours
									</span>
								</div>
								<div className="pt-2 space-y-2">
									<div className="flex justify-between">
										<span className="text-muted">Value Created:</span>
										<span className="font-semibold text-status-success-icon">
											${formatCompact(calculatedROI.valueCreated)}
										</span>
									</div>
									<div className="flex justify-between">
										<span className="text-muted">Token Cost:</span>
										<span className="font-semibold text-status-error-icon">
											-{formatCurrency(metrics.total_cost)}
										</span>
									</div>
									<div className="flex justify-between border-t-2 border-border pt-2 mt-2">
										<span className="text-foreground font-bold">
											Net Value:
										</span>
										<span className="font-bold text-accent text-lg">
											${formatCompact(calculatedROI.dollarValueSaved)}
										</span>
									</div>
									<div className="flex justify-between">
										<span className="text-foreground font-bold">ROI:</span>
										<span
											className={`font-bold text-lg ${
												calculatedROI.roiPercentage >= 0
													? "text-status-success-icon"
													: "text-status-error-icon"
											}`}
										>
											{formatPercent(calculatedROI.roiPercentage)}
										</span>
									</div>
								</div>
							</div>
						</div>
					</AnalyticsCard>

					{/* Trends Charts */}
					{trends && trends.length > 0 && (
						<div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
							<AnalyticsCard>
								<div className="mb-4">
									<h3 className="text-lg font-semibold text-heading">
										Weekly Cost Trend
									</h3>
									<p className="text-sm text-muted mt-1">
										Total spend over time
									</p>
								</div>
								<ResponsiveContainer width="100%" height={300}>
									<LineChart data={trends}>
										<CartesianGrid
											strokeDasharray="3 3"
											stroke={chartTheme.gridStroke}
										/>
										<XAxis
											dataKey="week_start"
											stroke={chartTheme.axisStroke}
											fontSize={12}
											tickFormatter={(value) =>
												new Date(value).toLocaleDateString("en-US", {
													month: "short",
													day: "numeric",
												})
											}
										/>
										<YAxis
											stroke={chartTheme.axisStroke}
											fontSize={12}
											tickFormatter={(value) => `$${value}`}
										/>
										<Tooltip
											contentStyle={{
												backgroundColor: chartTheme.tooltipBg,
												borderColor: chartTheme.tooltipBorder,
											}}
											formatter={(value) => [
												`$${((value as number) ?? 0).toFixed(2)}`,
												"Cost",
											]}
											labelFormatter={(label) =>
												`Week of ${new Date(label).toLocaleDateString()}`
											}
										/>
										<Line
											type="monotone"
											dataKey="total_cost"
											stroke="#3b82f6"
											strokeWidth={2}
											dot={{ r: 4 }}
										/>
									</LineChart>
								</ResponsiveContainer>
							</AnalyticsCard>

							<AnalyticsCard>
								<div className="mb-4">
									<h3 className="text-lg font-semibold text-heading">
										Weekly Productivity Score
									</h3>
									<p className="text-sm text-muted mt-1">
										Commits per dollar x 100
									</p>
								</div>
								<ResponsiveContainer width="100%" height={300}>
									<LineChart data={trends}>
										<CartesianGrid
											strokeDasharray="3 3"
											stroke={chartTheme.gridStroke}
										/>
										<XAxis
											dataKey="week_start"
											stroke={chartTheme.axisStroke}
											fontSize={12}
											tickFormatter={(value) =>
												new Date(value).toLocaleDateString("en-US", {
													month: "short",
													day: "numeric",
												})
											}
										/>
										<YAxis stroke={chartTheme.axisStroke} fontSize={12} />
										<Tooltip
											contentStyle={{
												backgroundColor: chartTheme.tooltipBg,
												borderColor: chartTheme.tooltipBorder,
											}}
											labelFormatter={(label) =>
												`Week of ${new Date(label).toLocaleDateString()}`
											}
										/>
										<Line
											type="monotone"
											dataKey="productivity_score"
											stroke="#10b981"
											strokeWidth={2}
											dot={{ r: 4 }}
											name="Productivity Score"
										/>
									</LineChart>
								</ResponsiveContainer>
							</AnalyticsCard>
						</div>
					)}

					{/* Cost Breakdown Tables */}
					<div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
						<AnalyticsCard>
							<h3 className="text-lg font-semibold text-heading mb-4">
								Developer Cost Breakdown
							</h3>
							<DataTable
								columns={devCostColumns}
								data={developerCosts ?? []}
								defaultSorting={[{ id: "cost", desc: true }]}
								defaultPageSize={50}
							/>
						</AnalyticsCard>

						<AnalyticsCard>
							<h3 className="text-lg font-semibold text-heading mb-4">
								Project Cost Breakdown
							</h3>
							<DataTable
								columns={projectCostColumns}
								data={projectCosts ?? []}
								defaultSorting={[{ id: "cost", desc: true }]}
								defaultPageSize={50}
							/>
						</AnalyticsCard>
					</div>
				</>
			)}
		</div>
	);
}

import {
	AlertCircle,
	BookOpen,
	Building2,
	Check,
	ChevronsLeft,
	ChevronsRight,
	ChevronsUpDown,
	Clock,
	DollarSign,
	FolderKanban,
	LayoutDashboard,
	LogOut,
	Mail,
	Plus,
	Settings,
	UserCircle,
} from "lucide-react";
import { useTheme } from "next-themes";
import { useState } from "react";
import { Link, useLocation } from "react-router-dom";
import { useOrganization } from "../../contexts/OrganizationContext";
import { useUserInvitations } from "../../hooks/useUserInvitations";
import { authClient, signOut } from "../../lib/auth-client";
import { cn } from "../../lib/utils";
import { Avatar, AvatarFallback, AvatarImage } from "../ui/avatar";
import {
	DropdownMenu,
	DropdownMenuContent,
	DropdownMenuItem,
	DropdownMenuSeparator,
	DropdownMenuTrigger,
} from "../ui/dropdown-menu";
import {
	Tooltip,
	TooltipContent,
	TooltipProvider,
	TooltipTrigger,
} from "../ui/tooltip";
import { ThemeToggle } from "./ThemeToggle";

const navigation = [
	{ name: "Overview", href: "/dashboard", icon: LayoutDashboard },
	{ name: "Developers", href: "/dashboard/developers", icon: UserCircle },
	{ name: "Projects", href: "/dashboard/projects", icon: FolderKanban },
	{
		name: "ROI & Business Value",
		href: "/dashboard/roi",
		icon: DollarSign,
	},
	{ name: "Sessions", href: "/dashboard/sessions", icon: Clock },
	{ name: "Learnings", href: "/dashboard/learnings", icon: BookOpen },
	{ name: "Errors", href: "/dashboard/errors", icon: AlertCircle },
];

function getInitials(name: string) {
	return name
		.split(" ")
		.map((part) => part[0])
		.join("")
		.toUpperCase()
		.slice(0, 2);
}

function OrgSwitcher({ collapsed }: { collapsed: boolean }) {
	const { activeOrg, organizations, switchOrg } = useOrganization();

	const handleSelect = async (orgId: string) => {
		if (orgId !== activeOrg?.id) {
			await switchOrg(orgId);
		}
	};

	return (
		<DropdownMenu>
			<DropdownMenuTrigger asChild>
				<button
					type="button"
					className={cn(
						"flex w-full items-center gap-1.5 px-4 h-10 overflow-hidden hover:bg-hover transition-colors",
						collapsed && "justify-center px-0",
					)}
				>
					<Building2 className="h-4 w-4 shrink-0 text-accent" />
					{!collapsed && (
						<>
							<span className="flex-1 truncate text-left text-sm font-bold text-heading">
								{activeOrg?.name ?? "Select org"}
							</span>
							<ChevronsUpDown className="h-3.5 w-3.5 shrink-0 text-muted" />
						</>
					)}
				</button>
			</DropdownMenuTrigger>
			<DropdownMenuContent
				side={collapsed ? "right" : "bottom"}
				align="start"
				className="w-56"
			>
				{organizations.map((org) => (
					<DropdownMenuItem key={org.id} onClick={() => handleSelect(org.id)}>
						<Building2 className="h-3.5 w-3.5 shrink-0 text-muted" />
						<span className="flex-1 truncate">{org.name}</span>
						{org.id === activeOrg?.id && (
							<Check className="h-3.5 w-3.5 shrink-0 text-accent" />
						)}
					</DropdownMenuItem>
				))}
				<DropdownMenuSeparator />
				<DropdownMenuItem asChild>
					<Link to="/dashboard/organization">
						<Settings className="h-3.5 w-3.5 shrink-0" />
						<span>Manage organization</span>
					</Link>
				</DropdownMenuItem>
				<DropdownMenuItem asChild>
					<Link to="/dashboard/organization/new">
						<Plus className="h-3.5 w-3.5 shrink-0" />
						<span>Create organization</span>
					</Link>
				</DropdownMenuItem>
			</DropdownMenuContent>
		</DropdownMenu>
	);
}

export function Sidebar() {
	const { pathname } = useLocation();
	const { data: session } = authClient.useSession();
	const [collapsed, setCollapsed] = useState(false);
	const { resolvedTheme } = useTheme();
	const { count: invitationCount } = useUserInvitations();

	const logoSrc =
		resolvedTheme === "dark" ? "/logo-light.svg" : "/logo-dark.svg";

	return (
		<TooltipProvider>
			<div
				className={cn(
					"relative flex h-full shrink-0 flex-col bg-surface border-r border-border z-20 transition-[width] duration-200 ease-in-out",
					collapsed ? "w-14" : "w-64",
				)}
			>
				<div className="flex items-center border-b border-border">
					<Link
						to="/dashboard"
						className={cn(
							"flex items-center shrink-0 px-4 h-10",
							collapsed && "px-3",
						)}
					>
						<img src={logoSrc} alt="Rudel" className="h-5 w-5" />
					</Link>
					<div className="flex-1 min-w-0">
						<OrgSwitcher collapsed={collapsed} />
					</div>
					<button
						type="button"
						onClick={() => setCollapsed(!collapsed)}
						className="p-1 mr-1 rounded-md text-muted hover:text-foreground hover:bg-hover transition-colors shrink-0"
						title={collapsed ? "Expand sidebar" : "Collapse sidebar"}
					>
						{collapsed ? (
							<ChevronsRight className="h-4 w-4" />
						) : (
							<ChevronsLeft className="h-4 w-4" />
						)}
					</button>
				</div>

				<nav className="flex-1 px-2 pt-2 pb-1 flex flex-col gap-[1px]">
					{navigation.map((item) => {
						const isActive = pathname === item.href;
						const Icon = item.icon;

						const link = (
							<Link
								to={item.href}
								className={cn(
									"flex items-center gap-2 rounded-lg px-2 py-2 text-[0.8125rem] font-medium transition-colors duration-150",
									collapsed && "justify-center",
									isActive
										? "bg-hover text-heading"
										: "text-muted hover:bg-hover hover:text-foreground",
								)}
							>
								<Icon className="h-4 w-4 shrink-0" />
								{!collapsed && (
									<span className="whitespace-nowrap overflow-hidden">
										{item.name}
									</span>
								)}
							</Link>
						);

						return (
							<div key={item.name}>
								{collapsed ? (
									<Tooltip>
										<TooltipTrigger asChild>{link}</TooltipTrigger>
										<TooltipContent side="right">{item.name}</TooltipContent>
									</Tooltip>
								) : (
									link
								)}
							</div>
						);
					})}
					{invitationCount > 0 &&
						(() => {
							const isActive = pathname === "/dashboard/invitations";
							const link = (
								<Link
									to="/dashboard/invitations"
									className={cn(
										"relative flex items-center gap-2 rounded-lg px-2 py-2 text-[0.8125rem] font-medium transition-colors duration-150",
										collapsed && "justify-center",
										isActive
											? "bg-hover text-heading"
											: "text-muted hover:bg-hover hover:text-foreground",
									)}
								>
									<span className="relative">
										<Mail className="h-4 w-4 shrink-0" />
										<span className="absolute -top-1.5 -right-1.5 flex h-3.5 w-3.5 items-center justify-center rounded-full bg-red-500 text-[0.5625rem] font-bold leading-none text-white">
											{invitationCount}
										</span>
									</span>
									{!collapsed && (
										<span className="whitespace-nowrap overflow-hidden">
											Invitations
										</span>
									)}
								</Link>
							);

							return (
								<div>
									{collapsed ? (
										<Tooltip>
											<TooltipTrigger asChild>{link}</TooltipTrigger>
											<TooltipContent side="right">
												Invitations ({invitationCount})
											</TooltipContent>
										</Tooltip>
									) : (
										link
									)}
								</div>
							);
						})()}
				</nav>

				{session?.user && (
					<div
						className={cn(
							"border-t border-border p-2 flex items-center gap-2",
							collapsed ? "justify-center" : "px-2",
						)}
					>
						{collapsed ? (
							<Tooltip>
								<TooltipTrigger asChild>
									<Link
										to="/dashboard/profile"
										className="flex items-center gap-2 min-w-0"
									>
										<Avatar size="sm" className="shrink-0">
											{session.user.image && (
												<AvatarImage
													src={session.user.image}
													alt={session.user.name}
												/>
											)}
											<AvatarFallback>
												{getInitials(session.user.name)}
											</AvatarFallback>
										</Avatar>
									</Link>
								</TooltipTrigger>
								<TooltipContent side="right">
									{session.user.name}
								</TooltipContent>
							</Tooltip>
						) : (
							<>
								<Link
									to="/dashboard/profile"
									className="flex-1 flex items-center gap-2 min-w-0"
								>
									<Avatar size="sm" className="shrink-0">
										{session.user.image && (
											<AvatarImage
												src={session.user.image}
												alt={session.user.name}
											/>
										)}
										<AvatarFallback>
											{getInitials(session.user.name)}
										</AvatarFallback>
									</Avatar>
									<span className="flex-1 truncate text-xs font-medium text-foreground hover:text-heading transition-colors">
										{session.user.name}
									</span>
								</Link>
								<ThemeToggle />
								<button
									type="button"
									onClick={() => signOut()}
									className="p-1 rounded-md text-muted hover:text-foreground hover:bg-hover transition-colors shrink-0"
									title="Sign out"
								>
									<LogOut className="h-3.5 w-3.5" />
								</button>
							</>
						)}
					</div>
				)}
			</div>
		</TooltipProvider>
	);
}

import { ChevronRight } from "lucide-react";
import { Link, useLocation } from "react-router-dom";
import { useUserMap } from "@/hooks/useUserMap";
import { formatUsername } from "@/lib/format";

const segmentLabels: Record<string, string> = {
	dashboard: "Overview",
	developers: "Developers",
	projects: "Projects",
	roi: "ROI & Business Value",
	sessions: "Sessions",
	learnings: "Learnings",
	errors: "Errors",
	invitations: "Invitations",
	profile: "Profile",
};

export function Breadcrumb() {
	const { pathname } = useLocation();
	const segments = pathname.split("/").filter(Boolean);

	const { userMap } = useUserMap();

	const crumbs = segments.map((segment, index) => {
		const href = `/${segments.slice(0, index + 1).join("/")}`;
		const prevSegment = index > 0 ? segments[index - 1] : null;
		const isDeveloperUserId = prevSegment === "developers";
		const label = isDeveloperUserId
			? formatUsername(segment, userMap)
			: segmentLabels[segment] || decodeURIComponent(segment);
		const isLast = index === segments.length - 1;

		return { href, label, isLast };
	});

	return (
		<nav className="flex shrink-0 items-center gap-1 text-xs text-muted h-10 px-8 bg-surface border-b border-border">
			{crumbs.map((crumb, index) => (
				<span key={crumb.href} className="flex items-center gap-1">
					{index > 0 && <ChevronRight className="h-3 w-3" />}
					{crumb.isLast ? (
						<span className="text-subheading">{crumb.label}</span>
					) : (
						<Link
							to={crumb.href}
							className="hover:text-foreground transition-colors"
						>
							{crumb.label}
						</Link>
					)}
				</span>
			))}
		</nav>
	);
}

