								<div className="mb-4">
									<div className="flex items-center gap-1.5">
										<h3 className="text-lg font-semibold text-heading">
											Weekly Productivity Score
										</h3>
										<TooltipProvider>
											<Tooltip>
												<TooltipTrigger asChild>
													<HelpCircle className="h-4 w-4 text-muted cursor-help shrink-0" />
												</TooltipTrigger>
												<TooltipContent className="max-w-xs">
													<p className="font-medium mb-1">
														Productivity Score formula:
													</p>
													<p className="font-mono text-xs">
														(commits ÷ total spend) × 100
													</p>
													<p className="text-xs text-muted mt-1">
														Higher is better — more commits delivered per dollar
														spent on Claude.
													</p>
												</TooltipContent>
											</Tooltip>
										</TooltipProvider>
									</div>
									<p className="text-sm text-muted mt-1">
										Commits per dollar x 100
									</p>
								</div>
								<ResponsiveContainer width="100%" height={300}>
									<LineChart data={trends}>
										<CartesianGrid
											strokeDasharray="3 3"
											stroke={chartTheme.gridStroke}
										/>
										<XAxis
											dataKey="week_start"
											stroke={chartTheme.axisStroke}
											fontSize={12}
											tickFormatter={(value) =>
												new Date(value).toLocaleDateString("en-US", {
													month: "short",
													day: "numeric",
												})
											}
										/>
										<YAxis stroke={chartTheme.axisStroke} fontSize={12} />
										<RechartsTooltip
											contentStyle={{
												backgroundColor: chartTheme.tooltipBg,
												borderColor: chartTheme.tooltipBorder,
											}}
											labelFormatter={(label) =>
												`Week of ${new Date(label).toLocaleDateString()}`
											}
										/>
										<Line
											type="monotone"
											dataKey="productivity_score"
											stroke="#10b981"
											strokeWidth={2}
											dot={{ r: 4 }}
											name="Productivity Score"
										/>
									</LineChart>
								</ResponsiveContainer>
							</AnalyticsCard>
						</div>
					)}

					{/* Cost Breakdown Tables */}
					<div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
						<AnalyticsCard>
							<h3 className="text-lg font-semibold text-heading mb-4">
								Developer Cost Breakdown
							</h3>
							<DataTable
								columns={devCostColumns}
								data={developerCosts ?? []}
								defaultSorting={[{ id: "cost", desc: true }]}
								defaultPageSize={10}
							/>
						</AnalyticsCard>

						<AnalyticsCard>
							<h3 className="text-lg font-semibold text-heading mb-4">
								Project Cost Breakdown
							</h3>
							<DataTable
								columns={projectCostColumns}
								data={projectCosts ?? []}
								defaultSorting={[{ id: "cost", desc: true }]}
								defaultPageSize={10}
							/>
						</AnalyticsCard>
					</div>
				</>
			)}
		</div>
	);
}

